$res = "android\app\src\main\res"

$bytes = [Convert]::FromBase64String("")
[IO.File]::WriteAllBytes("$PSScriptRoot\$res\mipmap-mdpi\ic_launcher.png", $bytes)
[IO.File]::WriteAllBytes("$PSScriptRoot\$res\mipmap-mdpi\ic_launcher_round.png", $bytes)
[IO.File]::WriteAllBytes("$PSScriptRoot\$res\mipmap-mdpi\ic_launcher_foreground.png", $bytes)
Write-Host "mipmap-mdpi done"

