$anydpi = "$PSScriptRoot\$res\mipmap-anydpi-v26"
New-Item -ItemType Directory -Force -Path $anydpi | Out-Null
@"
<?xml version="1.0" encoding="utf-8"?>
<adaptive-icon xmlns:android="http://schemas.android.com/apk/res/android">
    <background android:drawable="@color/ic_launcher_background"/>
    <foreground android:drawable="@mipmap/ic_launcher_foreground"/>
</adaptive-icon>
"@ | Set-Content "$anydpi\ic_launcher.xml" -Encoding UTF8
@"
<?xml version="1.0" encoding="utf-8"?>
<adaptive-icon xmlns:android="http://schemas.android.com/apk/res/android">
    <background android:drawable="@color/ic_launcher_background"/>
    <foreground android:drawable="@mipmap/ic_launcher_foreground"/>
</adaptive-icon>
"@ | Set-Content "$anydpi\ic_launcher_round.xml" -Encoding UTF8
Write-Host "Adaptive XML done"

$valuesDir = "$PSScriptRoot\$res\values"
New-Item -ItemType Directory -Force -Path $valuesDir | Out-Null
@"
<?xml version="1.0" encoding="utf-8"?>
<resources>
    <color name="ic_launcher_background">#000000</color>
</resources>
"@ | Set-Content "$valuesDir\ic_launcher_background.xml" -Encoding UTF8
Write-Host "All icons installed - rebuild the APK now"